if [[  "$*" == *PR* ]]
then
    test_arr[$LINENO]="make all DATA_TYPE=cint16 COEFF_TYPE=int16  FIR_LEN=24 SHIFT=15 DECIMATE_FACTOR=2 INTERPOLATE_FACTOR=3 INPUT_WINDOW_VSIZE=256 CASC_LEN=1 USE_COEFF_RELOAD=0 NUM_OUTPUTS=2 DUMP_VCD=1"
fi

if [[ "$*" == *fromGen* || "$*" == *all* ]]
then
    echo "trying to reading genMake.txt"
    readarray -t my_arr <  ${dirOfRunmake}/genMake.txt
    echo "${my_arr[@]}"
    test_arr+=("${my_arr[@]}")
fi

if [[ "$*" == *fullSweep* || "$*" == *all* ]]
then

    types=(
        int16 int16
        cint16 int16
        int32 int16
        cint32 int16
        cint16 cint16
        int32 int32
        cint32 int32
        cint32 cint32
        float float
        cfloat float
        cfloat cfloat
    )

    # Original ideal set of params to sweep across
    lengths=(4 8 12 16 20 32 44 56 64 96 128 156 188 220 240)
    windows=(4 8 16 32 64 128 156 3188 220 256 320 384 512 1024)
    cascades=(1 2 3 4 5 6 7)

    #reduced to limit number of tests
    # Only one type combo
    types=(
        cint16 int16
    )
    #lengths=(16 20 44 56 96 128 188 240)
    #windows=(16 32 64 128 188 256 320 512 1024)
    # TODO support cascades
    cascades=(1)

    lengths=(4 20) # to be multiplied by interp rate
    interps=(1 2 3 4 5 7 8)
    decimates=(1 2 3 4 5 6 7 8)

    for (( typeI=0; typeI<${#types[@]}; typeI+=2 )); do
        echo "${types[$typeI]},${types[`expr $typeI + 1 `]}"
        dType=${types[$typeI]}
        cType=${types[`expr $typeI + 1 `]}
        # Scrape int number from coef type
        shift=${cType#*int}
        if [[ $cType == *float ]]; then
            shift=0
        fi
        for iRate in "${interps[@]}"; do
            for dRate in "${decimates[@]}"; do
                redLen=($(expr $iRate*4) $(expr $iRate*20))
                for fLen in "${redLen[@]}"; do
                    if [[ $dRate -lt $iRate && $(( $iRate % $dRate )) -ne 0 ]]; then
                        for cLen in "${cascades[@]}"; do
                            redWindows=(${windows[@]})
                            # to reduce number of tests, limited number of windows
                            if [ $cLen -gt 1 ]; then
                                redWindows=(256 1024)
                            fi
                            # Always use a window of FIR Len
                            #test_arr[$LINENO]="make all DATA_TYPE=$dType COEFF_TYPE=$cType FIR_LEN=$fLen INTERPOLATE_FACTOR=$iRate DECIMATE_FACTOR=$dRate CASC_LEN=$cLen SHIFT=$shift INPUT_WINDOW_VSIZE=$fLen"
                            #echo ${redWindows[@]}
                            for wSize in "${redWindows[@]}"; do
                                if [ $wSize -gt $fLen ]
                                then
                                    #echo "DATA_TYPE=$dType COEFF_TYPE=$cType FIR_LEN=$fLen  CASC_LEN=$cLen SHIFT=$shift"
                                    echo "DATA_TYPE=$dType COEFF_TYPE=$cType FIR_LEN=$fLen INTERPOLATE_FACTOR=$iRate DECIMATE_FACTOR=$dRate CASC_LEN=$cLen SHIFT=$shift INPUT_WINDOW_VSIZE=$wSize"
                                    #test_arr[$LINENO]="make all DATA_TYPE=$dType COEFF_TYPE=$cType FIR_LEN=$fLen INTERPOLATE_FACTOR=$iRate DECIMATE_FACTOR=$dRate CASC_LEN=$cLen SHIFT=$shift INPUT_WINDOW_VSIZE=$wSize"
                                    #test_arr[${#test_arr[*]}]
                                    #echo "wSize $wSize"
                                fi
                            done #wSize
                        done #cLen
                    fi #dRate<iRate
                done #fLen
            done #dRate
        done #iRate
    done #typeI
fi

# Randomized testing
if [[ "$*" == *randomized* ]]
then
    # read from randomized test file
    while IFS= read -r line; do
        test_arr[${#test_arr[*]}]="$line"
    done < randomized_tests.txt
fi

# echo "Adding the following args to make commands: ${make_args[@]}"
# Ensure each test goes into a seperate runmake
for i in "${!test_arr[@]}"; do
    # append make args to each make command
    if [[ ${test_arr[$i]} == make* ]]
    then
        test_arr[$i]="${test_arr[$i]} ${make_args[@]}"
    fi
    test_arr[$i]="${test_arr[$i]} |& tee runmake_logs/runmake_${i}.log "
done

makeCmd_raw=()
otherCmd_raw=()

for i in "${!test_arr[@]}"; do
    # append make args to each make command
    if [[ ${test_arr[$i]} == make* ]]; then
        makeCmd_raw[${#makeCmd_raw[*]}]=${test_arr[$i]}
    else
        otherCmd_raw[${#otherCmd_raw[*]}]=${test_arr[$i]}
    fi
done
